extra.modelCss:
/* Unidades na prática */

html {
  font-size: 16px; /* 1rem = 16px */
}

.card {
  padding: 1rem;        /* 16px */
  border: 1px solid #ddd; /* px é perfeito aqui */
  border-radius: 12px;
  max-width: 90%;       /* % relativo ao pai */
}

.hero {
  min-height: 60vh;     /* relativo à altura da tela */
}

h1 {
  font-size: 2rem;      /* 32px */
}

p {
  font-size: 1rem;      /* 16px */
  line-height: 1.6;
}
